    }
    public static void main(String[] args) {
        try { validate(16); }
        catch (InvalidAgeException e) { System.out.println(e.getMessage()); }
    }
}

import java.io.*;

public class FinallyDemo {
    public static void main(String[] args) {
        FileWriter fw = null;
        try {
            fw = new FileWriter("log.txt");
            fw.write("Transaction started");
            throw new RuntimeException("Simulated error");
        } catch (IOException e) {
            System.out.println("IO Error");
        } catch (RuntimeException e) {
            System.out.println("Runtime Error");
        } finally {
            System.out.println("Cleanup always runs");
        }
    }
}

public class FinallySkipDemo {
    static int test() {
        try { return 1; }
        finally { System.out.println("Finally runs before return"); }
    }
    public static void main(String[] args) {
        System.out.println("Result: " + test());
        try { System.exit(0); }
        finally { System.out.println("Never printed"); }
    }
}

class InsufficientStockException extends Exception {
